                          <button
                            onClick={(e) => {
                              e.preventDefault(); 
                              e.stopPropagation();

                              const currentErrors = JSON.parse(localStorage.getItem('protocol-errors') || '[]');

                              const newError = {
                                id: `boundary-${question.id}-${Date.now()}`,
                                title: language === 'de' 
