import { ProtocolError } from '@shared/schema';
import XLSX from 'xlsx';
import { localFileService } from './local-file-service';

export class LocalErrorService {
  /**
   * Generate Excel error list from protocol errors
   */
  async generateErrorExcel(
    errors: ProtocolError[],
    protocolData: {
      buildingAddress?: string;
      liftId?: string;
      inspectorName?: string;
      inspectionDate?: string;
    },
    language: string = 'hu'
  ): Promise<Buffer> {
    const t = this.getTranslations(language);

    // Create workbook
    const workbook = XLSX.utils.book_new();

    // Header data
    const headerData = [
      [t.title],
      [''],
      [t.building, protocolData.buildingAddress || ''],
      [t.liftId, protocolData.liftId || ''],
      [t.inspector, protocolData.inspectorName || ''],
      [t.date, protocolData.inspectionDate || new Date().toLocaleDateString()],
      [''],
      [t.totalErrors, errors.length.toString()],
      ['']
    ];

    // Error list headers
    const errorHeaders = [
      [t.number, t.severity, t.title, t.description, t.photos]
    ];

    // Error data
    const errorData = errors.map((error, index) => [
      (index + 1).toString(),
      this.getSeverityText(error.severity, language),
      error.title,
      error.description,
      error.images?.length ? `${error.images.length} ${t.photo}` : t.noPhotos
    ]);

    // Summary data
    const criticalCount = errors.filter(e => e.severity === 'critical').length;
    const mediumCount = errors.filter(e => e.severity === 'medium').length;
    const lowCount = errors.filter(e => e.severity === 'low').length;

    const summaryData = [
      [''],
      [t.summary],
      [t.critical, criticalCount.toString()],
      [t.medium, mediumCount.toString()],
      [t.low, lowCount.toString()],
      [''],
      [t.generatedOn, new Date().toLocaleString()]
    ];

    // Combine all data
    const allData = [
      ...headerData,
      ...errorHeaders,
      ...errorData,
      ...summaryData
    ];

    // Create worksheet
    const worksheet = XLSX.utils.aoa_to_sheet(allData);

    // Set column widths
    worksheet['!cols'] = [
      { width: 8 },  // Number
      { width: 12 }, // Severity
      { width: 30 }, // Title
      { width: 50 }, // Description
      { width: 15 }  // Photos
    ];

    // Style the header
    if (worksheet['A1']) {
      worksheet['A1'].s = {
        font: { bold: true, size: 16 },
        alignment: { horizontal: 'center' }
      };
    }

    // Style error headers
    const headerRowIndex = headerData.length;
    for (let col = 0; col < 5; col++) {
      const cellRef = XLSX.utils.encode_cell({ r: headerRowIndex, c: col });
      if (worksheet[cellRef]) {
        worksheet[cellRef].s = {
          font: { bold: true },
          fill: { fgColor: { rgb: '366FB3' } },
          alignment: { horizontal: 'center' }
        };
      }
    }

    // Add worksheet to workbook
    XLSX.utils.book_append_sheet(workbook, worksheet, t.errorList);

    // Generate buffer
    const buffer = XLSX.write(workbook, { type: 'buffer', bookType: 'xlsx' });

    console.log(`Generated error Excel with ${errors.length} errors`);
    return buffer;
  }

  /**
   * Generate PDF error list from protocol errors
   */
  async generateErrorPDF(
    errors: ProtocolError[],
    protocolData: {
      buildingAddress?: string;
      liftId?: string;
      inspectorName?: string;
      inspectionDate?: string;
    },
    language: string = 'hu'
  ): Promise<Buffer> {
    // First generate Excel, then convert to PDF
    const excelBuffer = await this.generateErrorExcel(errors, protocolData, language);

    // Save Excel temporarily and convert to PDF
    const excelPath = await localFileService.saveErrorList(excelBuffer, 'excel');

    try {
      // Use LibreOffice to convert Excel to PDF
      const { spawn } = require('child_process');
      const path = require('path');
      const fs = require('fs');

      const tempDir = path.dirname(excelPath);
      const baseName = path.basename(excelPath, '.xlsx');
      const pdfPath = path.join(tempDir, `${baseName}.pdf`);

      return new Promise((resolve, reject) => {
        const process = spawn('libreoffice', [
          '--headless',
          '--convert-to', 'pdf',
          '--outdir', tempDir,
          excelPath
        ]);

        let stderr = '';
        process.stderr?.on('data', (data) => {
          stderr += data.toString();
        });

        process.on('close', (code) => {
          if (code === 0 && fs.existsSync(pdfPath)) {
            const pdfBuffer = fs.readFileSync(pdfPath);

            // Cleanup
            try {
              fs.unlinkSync(excelPath);
              fs.unlinkSync(pdfPath);
            } catch (e) {
              console.warn('Cleanup warning:', e.message);
            }

            resolve(pdfBuffer);
          } else {
            console.warn('LibreOffice conversion failed, generating HTML-based PDF');
            // Fallback to HTML-based PDF generation
            this.generateHTMLBasedPDF(errors, protocolData, language)
              .then(resolve)
              .catch(reject);
          }
        });

        // Timeout after 30 seconds
        setTimeout(() => {
          process.kill();
          reject(new Error('PDF conversion timeout'));
        }, 30000);
      });
    } catch (error) {
      console.error('PDF generation error:', error);
      // Fallback to HTML-based PDF
      return this.generateHTMLBasedPDF(errors, protocolData, language);
    }
  }

  /**
   * Fallback HTML-based PDF generation
   */
  private async generateHTMLBasedPDF(
    errors: ProtocolError[],
    protocolData: any,
    language: string
  ): Promise<Buffer> {
    const t = this.getTranslations(language);

    // Generate HTML content
    const html = `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="utf-8">
        <title>${t.errorList}</title>
        <style>
          body { font-family: Arial, sans-serif; margin: 20px; }
          .header { text-align: center; margin-bottom: 30px; }
          .info { margin-bottom: 20px; }
          .error-table { width: 100%; border-collapse: collapse; margin-bottom: 30px; }
          .error-table th, .error-table td { border: 1px solid #ccc; padding: 8px; text-align: left; }
          .error-table th { background-color: #366FB3; color: white; }
          .summary { margin-top: 30px; }
          .severity-critical { color: #dc3545; font-weight: bold; }
          .severity-medium { color: #ffc107; font-weight: bold; }
          .severity-low { color: #007bff; font-weight: bold; }
        </style>
      </head>
      <body>
        <div class="header">
          <h1>${t.title}</h1>
        </div>

        <div class="info">
          <p><strong>${t.building}:</strong> ${protocolData.buildingAddress || ''}</p>
          <p><strong>${t.liftId}:</strong> ${protocolData.liftId || ''}</p>
          <p><strong>${t.inspector}:</strong> ${protocolData.inspectorName || ''}</p>
          <p><strong>${t.date}:</strong> ${protocolData.inspectionDate || new Date().toLocaleDateString()}</p>
          <p><strong>${t.totalErrors}:</strong> ${errors.length}</p>
        </div>

        <table class="error-table">
          <thead>
            <tr>
              <th>${t.number}</th>
              <th>${t.severity}</th>
              <th>${t.title}</th>
              <th>${t.description}</th>
              <th>${t.photos}</th>
            </tr>
          </thead>
          <tbody>
            ${errors.map((error, index) => `
              <tr>
                <td>${index + 1}</td>
                <td class="severity-${error.severity}">${this.getSeverityText(error.severity, language)}</td>
                <td>${error.title}</td>
                <td>${error.description}</td>
                <td>${error.images?.length ? `${error.images.length} ${t.photo}` : t.noPhotos}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>

        <div class="summary">
          <h3>${t.summary}</h3>
          <p><span class="severity-critical">${t.critical}:</span> ${errors.filter(e => e.severity === 'critical').length}</p>
          <p><span class="severity-medium">${t.medium}:</span> ${errors.filter(e => e.severity === 'medium').length}</p>
          <p><span class="severity-low">${t.low}:</span> ${errors.filter(e => e.severity === 'low').length}</p>
        </div>

        <div style="margin-top: 40px; text-align: center; font-size: 12px; color: #666;">
          <p>${t.generatedOn}: ${new Date().toLocaleString()}</p>
          <p>OTIS APROD - ${t.protocolApp}</p>
        </div>
      </body>
      </html>
    `;

    // Convert HTML to PDF using puppeteer (if available) or return HTML as fallback
    try {
      const puppeteer = require('puppeteer');
      const browser = await puppeteer.launch({ headless: true });
      const page = await browser.newPage();

      await page.setContent(html);
      const pdfBuffer = await page.pdf({
        format: 'A4',
        margin: { top: '20mm', right: '15mm', bottom: '20mm', left: '15mm' }
      });

      await browser.close();
      return pdfBuffer;
    } catch (error) {
      console.warn('Puppeteer not available, returning HTML as fallback');
      // Return HTML as buffer - browser can handle this
      return Buffer.from(html, 'utf-8');
    }
  }

  /**
   * Get translations for error list generation
   */
  private getTranslations(language: string) {
    if (language === 'de') {
      return {
        title: 'OTIS Fehlerliste',
        building: 'Gebäude',
        liftId: 'Aufzug ID',
        inspector: 'Prüfer',
        date: 'Datum',
        totalErrors: 'Gesamtfehler',
        number: 'Nr.',
        severity: 'Schwere',
        title: 'Titel',
        description: 'Beschreibung',
        photos: 'Fotos',
        photo: 'Foto',
        noPhotos: 'Keine Fotos',
        summary: 'Zusammenfassung',
        critical: 'Kritisch',
        medium: 'Mittel',
        low: 'Niedrig',
        generatedOn: 'Erstellt am',
        errorList: 'Fehlerliste',
        protocolApp: 'Abnahmeprotokoll Anwendung'
      };
    } else {
      return {
        title: 'OTIS Hibalista',
        building: 'Épület',
        liftId: 'Lift ID',
        inspector: 'Ellenőr',
        date: 'Dátum',
        totalErrors: 'Összes hiba',
        number: 'Sz.',
        severity: 'Súlyosság',
        title: 'Cím',
        description: 'Leírás',
        photos: 'Fotók',
        photo: 'fotó',
        noPhotos: 'Nincs fotó',
        summary: 'Összegzés',
        critical: 'Kritikus',
        medium: 'Közepes',
        low: 'Alacsony',
        generatedOn: 'Generálva',
        errorList: 'Hibalista',
        protocolApp: 'Átvételi Protokoll Alkalmazás'
      };
    }
  }

  /**
   * Get severity text in specified language
   */
  private getSeverityText(severity: string, language: string): string {
    const translations = this.getTranslations(language);

    switch (severity) {
      case 'critical': return translations.critical;
      case 'medium': return translations.medium;
      case 'low': return translations.low;
      default: return severity;
    }
  }
}

// Export singleton instance
export const localErrorService = new LocalErrorService();

server/services/local-file-service.ts.content:
import fs from 'fs';
import path from 'path';
import { nanoid } from 'nanoid';

export class LocalFileService {
  private dataDir: string;
  private templatesDir: string;
  private protocolsDir: string;
  private errorsDir: string;
  private imagesDir: string;

  constructor() {
    this.dataDir = path.join(process.cwd(), 'data');
    this.templatesDir = path.join(this.dataDir, 'templates');
    this.protocolsDir = path.join(this.dataDir, 'protocols');
    this.errorsDir = path.join(this.dataDir, 'errors');
    this.imagesDir = path.join(this.dataDir, 'images');

    this.initializeDirectories();
  }

  private initializeDirectories() {
    const dirs = [this.dataDir, this.templatesDir, this.protocolsDir, this.errorsDir, this.imagesDir];

    dirs.forEach(dir => {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
        console.log(`Created directory: ${dir}`);
      }
    });
  }

  // Template file operations
  async saveTemplate(file: Express.Multer.File, type: string, language: string): Promise<string> {
    const fileId = nanoid();
    const extension = path.extname(file.originalname);
    const fileName = `${fileId}_${type}_${language}${extension}`;
    const filePath = path.join(this.templatesDir, fileName);

    // Copy file from upload location to templates directory
    fs.copyFileSync(file.path, filePath);

    // Clean up original uploaded file
    fs.unlinkSync(file.path);

    console.log(`Template saved locally: ${filePath}`);
    return filePath;
  }

  async getTemplate(filePath: string): Promise<Buffer> {
    if (!fs.existsSync(filePath)) {
      throw new Error(`Template file not found: ${filePath}`);
    }
    return fs.readFileSync(filePath);
  }

  async deleteTemplate(filePath: string): Promise<void> {
    if (fs.existsSync(filePath)) {
      fs.unlinkSync(filePath);
      console.log(`Template deleted: ${filePath}`);
    }
  }

  // Protocol file operations
  async saveProtocol(protocolData: any, format: 'excel' | 'pdf'): Promise<string> {
    const fileId = nanoid();
    const timestamp = new Date().toISOString().slice(0, 10);
    const fileName = `OTIS_Protocol_${timestamp}_${fileId}.${format === 'excel' ? 'xlsx' : 'pdf'}`;
    const filePath = path.join(this.protocolsDir, fileName);

    if (format === 'excel') {
      // Save Excel buffer
      fs.writeFileSync(filePath, protocolData);
    } else {
      // Save PDF buffer
      fs.writeFileSync(filePath, protocolData);
    }

    console.log(`Protocol saved locally: ${filePath}`);
    return filePath;
  }

  async getProtocol(filePath: string): Promise<Buffer> {
    if (!fs.existsSync(filePath)) {
      throw new Error(`Protocol file not found: ${filePath}`);
    }
    return fs.readFileSync(filePath);
  }

  // Error list file operations
  async saveErrorList(errorData: any, format: 'excel' | 'pdf'): Promise<string> {
    const fileId = nanoid();
    const timestamp = new Date().toISOString().slice(0, 10);
    const fileName = `OTIS_Errors_${timestamp}_${fileId}.${format === 'excel' ? 'xlsx' : 'pdf'}`;
    const filePath = path.join(this.errorsDir, fileName);

    fs.writeFileSync(filePath, errorData);

    console.log(`Error list saved locally: ${filePath}`);
    return filePath;
  }

  async getErrorList(filePath: string): Promise<Buffer> {
    if (!fs.existsSync(filePath)) {
      throw new Error(`Error list file not found: ${filePath}`);
    }
    return fs.readFileSync(filePath);
  }

  // Image file operations
  async saveImage(imageData: Buffer, originalName: string): Promise<string> {
    const fileId = nanoid();
    const extension = path.extname(originalName);
    const fileName = `${fileId}${extension}`;
    const filePath = path.join(this.imagesDir, fileName);

    fs.writeFileSync(filePath, imageData);

    console.log(`Image saved locally: ${filePath}`);
    return filePath;
  }

  async getImage(filePath: string): Promise<Buffer> {
    if (!fs.existsSync(filePath)) {
      throw new Error(`Image file not found: ${filePath}`);
    }
    return fs.readFileSync(filePath);
  }

  // Utility methods
  getFileStats(filePath: string): fs.Stats | null {
    try {
      return fs.statSync(filePath);
    } catch {
      return null;
    }
  }

  listFiles(directory: 'templates' | 'protocols' | 'errors' | 'images'): string[] {
    const dirPath = path.join(this.dataDir, directory);
    try {
      return fs.readdirSync(dirPath);
    } catch {
      return [];
    }
  }

  // Cleanup old files (older than specified days)
  cleanupOldFiles(directory: 'protocols' | 'errors', olderThanDays: number = 30): void {
    const dirPath = path.join(this.dataDir, directory);
    const cutoffTime = Date.now() - (olderThanDays * 24 * 60 * 60 * 1000);

    try {
      const files = fs.readdirSync(dirPath);
      let deletedCount = 0;

      files.forEach(file => {
        const filePath = path.join(dirPath, file);
        const stats = fs.statSync(filePath);

        if (stats.mtime.getTime() < cutoffTime) {
          fs.unlinkSync(filePath);
          deletedCount++;
        }
      });

      if (deletedCount > 0) {
        console.log(`Cleaned up ${deletedCount} old files from ${directory}`);
      }
    } catch (error) {
      console.error(`Error cleaning up ${directory}:`, error);
    }
  }
}

// Export singleton instance
export const localFileService = new LocalFileService();

server/services/local-storage-service.ts.content:
import { sqlite } from '../local-db';
import { ProtocolError } from '@shared/schema';
import { localFileService } from './local-file-service';

interface Template {
  id: string;
  name: string;
  type: string;
  language: string;
  fileName: string;
  filePath: string;
  isActive: boolean;
  uploadedAt: string;
}

interface Protocol {
  id: string;
  answers: Record<string, any>;
  errors: ProtocolError[];
  signatureData?: string;
  signatureName?: string;
  receptionDate: string;
  language: string;
  createdAt: string;
}

interface QuestionConfig {
  id: string;
  templateId: string;
  questionId: string;
  cellReference: string;
  type: string;
}

export class LocalStorageService {
  // Template operations
  async saveTemplate(template: Omit<Template, 'id' | 'uploadedAt'>): Promise<string> {
    const id = `tmpl_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    const uploadedAt = new Date().toISOString();

    const stmt = sqlite.prepare(`
      INSERT INTO templates (id, name, type, language, file_name, file_path, is_active, uploaded_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `);

    stmt.run(id, template.name, template.type, template.language, template.fileName, template.filePath, template.isActive, uploadedAt);

    console.log(`Template saved to local database: ${id}`);
    return id;
  }

  async getActiveTemplate(type: string, language: string): Promise<Template | null> {
    const stmt = sqlite.prepare(`
      SELECT * FROM templates 
      WHERE type = ? AND language = ? AND is_active = 1
      ORDER BY uploaded_at DESC 
      LIMIT 1
    `);

    const row = stmt.get(type, language) as any;
    if (!row) return null;

    return {
      id: row.id,
      name: row.name,
      type: row.type,
      language: row.language,
      fileName: row.file_name,
      filePath: row.file_path,
      isActive: Boolean(row.is_active),
      uploadedAt: row.uploaded_at
    };
  }

  async getAllTemplates(): Promise<Template[]> {
    const stmt = sqlite.prepare('SELECT * FROM templates ORDER BY uploaded_at DESC');
    const rows = stmt.all() as any[];

    return rows.map(row => ({
      id: row.id,
      name: row.name,
      type: row.type,
      language: row.language,
      fileName: row.file_name,
      filePath: row.file_path,
      isActive: Boolean(row.is_active),
      uploadedAt: row.uploaded_at
    }));
  }

  async setTemplateActive(id: string, isActive: boolean): Promise<void> {
    const stmt = sqlite.prepare('UPDATE templates SET is_active = ? WHERE id = ?');
    stmt.run(isActive, id);
    console.log(`Template ${id} set to ${isActive ? 'active' : 'inactive'}`);
  }

  async deleteTemplate(id: string): Promise<void> {
    // Get template info before deleting
    const getStmt = sqlite.prepare('SELECT file_path FROM templates WHERE id = ?');
    const template = getStmt.get(id) as any;

    if (template) {
      // Delete file from filesystem
      await localFileService.deleteTemplate(template.file_path);
    }

    // Delete from database
    const deleteStmt = sqlite.prepare('DELETE FROM templates WHERE id = ?');
    deleteStmt.run(id);
    console.log(`Template deleted: ${id}`);
  }

  // Protocol operations
  async saveProtocol(protocol: Omit<Protocol, 'id' | 'createdAt'>): Promise<string> {
    const id = `prot_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    const createdAt = new Date().toISOString();

    const stmt = sqlite.prepare(`
      INSERT INTO protocols (id, answers, errors, signature_data, signature_name, reception_date, language, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `);

    stmt.run(
      id,
      JSON.stringify(protocol.answers),
      JSON.stringify(protocol.errors),
      protocol.signatureData || null,
      protocol.signatureName || null,
      protocol.receptionDate,
      protocol.language,
      createdAt
    );

    console.log(`Protocol saved to local database: ${id}`);
    return id;
  }

  async getProtocol(id: string): Promise<Protocol | null> {
    const stmt = sqlite.prepare('SELECT * FROM protocols WHERE id = ?');
    const row = stmt.get(id) as any;

    if (!row) return null;

    return {
      id: row.id,
      answers: JSON.parse(row.answers || '{}'),
      errors: JSON.parse(row.errors || '[]'),
      signatureData: row.signature_data,
      signatureName: row.signature_name,
      receptionDate: row.reception_date,
      language: row.language,
      createdAt: row.created_at
    };
  }

  async getAllProtocols(): Promise<Protocol[]> {
    const stmt = sqlite.prepare('SELECT * FROM protocols ORDER BY created_at DESC');
    const rows = stmt.all() as any[];

    return rows.map(row => ({
      id: row.id,
      answers: JSON.parse(row.answers || '{}'),
      errors: JSON.parse(row.errors || '[]'),
      signatureData: row.signature_data,
      signatureName: row.signature_name,
      receptionDate: row.reception_date,
      language: row.language,
      createdAt: row.created_at
    }));
  }

  // Question config operations
  async saveQuestionConfig(config: Omit<QuestionConfig, 'id'>): Promise<string> {
    const id = `qc_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;

    const stmt = sqlite.prepare(`
      INSERT INTO question_configs (id, template_id, question_id, cell_reference, type, created_at)
      VALUES (?, ?, ?, ?, ?, ?)
    `);

    stmt.run(id, config.templateId, config.questionId, config.cellReference, config.type, new Date().toISOString());

    return id;
  }

  async getQuestionConfigsByTemplate(templateId: string): Promise<QuestionConfig[]> {
    const stmt = sqlite.prepare('SELECT * FROM question_configs WHERE template_id = ?');
    const rows = stmt.all(templateId) as any[];

    return rows.map(row => ({
      id: row.id,
      templateId: row.template_id,
      questionId: row.question_id,
      cellReference: row.cell_reference,
      type: row.type
    }));
  }

  // Utility operations
  async cleanupOldProtocols(olderThanDays: number = 90): Promise<void> {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - olderThanDays);

    const stmt = sqlite.prepare('DELETE FROM protocols WHERE created_at < ?');
    const result = stmt.run(cutoffDate.toISOString());

    console.log(`Cleaned up ${result.changes} old protocols`);
  }

  async getDatabaseStats(): Promise<any> {
    const templatesCount = sqlite.prepare('SELECT COUNT(*) as count FROM templates').get() as any;
    const protocolsCount = sqlite.prepare('SELECT COUNT(*) as count FROM protocols').get() as any;
    const configsCount = sqlite.prepare('SELECT COUNT(*) as count FROM question_configs').get() as any;

    return {
      templates: templatesCount.count,
      protocols: protocolsCount.count,
      questionConfigs: configsCount.count
    };
  }
}

// Export singleton instance
export const localStorage = new LocalStorageService();

